61: void ActiveStreamFilterBase::commonContinue() {
62:   if (!canContinue()) {
63:     ENVOY_STREAM_LOG(trace, "cannot continue filter chain: filter={}", *this,
64:                      static_cast<const void*>(this));
65:     return;
66:   }
67: 
68:   // Set ScopeTrackerScopeState if there's no existing crash context.
69:   ScopeTrackedObjectStack encapsulated_object;
70:   absl::optional<ScopeTrackerScopeState> state;
71:   if (parent_.dispatcher_.trackedObjectStackIsEmpty()) {
72:     restoreContextOnContinue(encapsulated_object);
73:     state.emplace(&encapsulated_object, parent_.dispatcher_);
74:   }
75: 
76:   ENVOY_STREAM_LOG(trace, "continuing filter chain: filter={}", *this,
77:                    static_cast<const void*>(this));
78:   ASSERT(!canIterate(),
79:          "Attempting to continue iteration while the IterationState is already Continue");
80:   // If iteration has stopped for all frame types, set iterate_from_current_filter_ to true so the
81:   // filter iteration starts with the current filter instead of the next one.
82:   if (stoppedAll()) {
83:     iterate_from_current_filter_ = true;
84:   }
85:   allowIteration();
86: 
87:   // Only resume with do1xxHeaders() if we've actually seen 1xx headers.
88:   if (has1xxHeaders()) {
89:     continued_1xx_headers_ = true;
90:     do1xxHeaders();
91:     // If the response headers have not yet come in, don't continue on with
92:     // headers and body. doHeaders expects request headers to exist.
93:     if (!parent_.filter_manager_callbacks_.responseHeaders()) {
94:       return;
95:     }
96:   }
97: 
98:   if (!canContinue()) {
99:     ENVOY_STREAM_LOG(trace, "cannot continue filter chain: filter={}", *this,
100:                      static_cast<const void*>(this));
101:     return;
102:   }
103: 
104:   // Make sure that we handle the zero byte data frame case. We make no effort to optimize this
105:   // case in terms of merging it into a header only request/response. This could be done in the
106:   // future.
107:   if (!headers_continued_) {
108:     headers_continued_ = true;
109:     doHeaders(observedEndStream() && !bufferedData() && !hasTrailers());
110:   }
111: 
112:   if (!canContinue()) {
113:     ENVOY_STREAM_LOG(trace, "cannot continue filter chain: filter={}", *this,
114:                      static_cast<const void*>(this));
115:     return;
116:   }
117: 
118:   doMetadata();
119: 
120:   if (!canContinue()) {
121:     ENVOY_STREAM_LOG(trace, "cannot continue filter chain: filter={}", *this,
122:                      static_cast<const void*>(this));
123:     return;
124:   }
125: 
126:   // It is possible for trailers to be added during doData(). doData() itself handles continuation
127:   // of trailers for the non-continuation case. Thus, we must keep track of whether we had
128:   // trailers prior to calling doData(). If we do, then we continue them here, otherwise we rely
129:   // on doData() to do so.
130:   const bool had_trailers_before_data = hasTrailers();
131:   if (bufferedData()) {
132:     doData(observedEndStream() && !had_trailers_before_data);
133:   }
134: 
135:   if (!canContinue()) {
136:     ENVOY_STREAM_LOG(trace, "cannot continue filter chain: filter={}", *this,
137:                      static_cast<const void*>(this));
138:     return;
139:   }
140: 
141:   if (had_trailers_before_data) {
142:     doTrailers();
143:   }
144: 
145:   iterate_from_current_filter_ = false;
146: }
