28: TEST_F(HttpConnectionManagerImplTest, HeaderOnlyRequestAndResponse) {
29:   setup(SetupOpts().setTracing(false));
30: 
31:   // Store the basic request encoder during filter chain setup.
32:   std::shared_ptr<MockStreamDecoderFilter> filter(new NiceMock<MockStreamDecoderFilter>());
33: 
34:   EXPECT_CALL(*filter, decodeHeaders(_, true))
35:       .Times(2)
36:       .WillRepeatedly(Invoke([&](RequestHeaderMap& headers, bool) -> FilterHeadersStatus {
37:         EXPECT_NE(nullptr, headers.ForwardedFor());
38:         EXPECT_EQ("http", headers.getForwardedProtoValue());
39:         if (headers.Path()->value() == "/healthcheck") {
40:           filter->callbacks_->streamInfo().healthCheck(true);
41:         }
42: 
43:         return FilterHeadersStatus::StopIteration;
44:       }));
45: 
46:   EXPECT_CALL(*filter, setDecoderFilterCallbacks(_)).Times(2);
47: 
48:   EXPECT_CALL(filter_factory_, createFilterChain(_))
49:       .Times(2)
50:       .WillRepeatedly(Invoke([&](FilterChainFactoryCallbacks& callbacks) -> bool {
51:         auto factory = createDecoderFilterFactoryCb(filter);
52:         callbacks.setFilterConfigName("");
53:         factory(callbacks);
54:         return true;
55:       }));
56: 
57:   EXPECT_CALL(filter_callbacks_.connection_.dispatcher_, deferredDelete_(_)).Times(2);
58: 
59:   // When dispatch is called on the codec, we pretend to get a new stream and then fire a headers
60:   // only request into it. Then we respond into the filter.
61:   EXPECT_CALL(*codec_, dispatch(_))
62:       .Times(2)
63:       .WillRepeatedly(Invoke([&](Buffer::Instance& data) -> Http::Status {
64:         EXPECT_CALL(response_encoder_.stream_, codecStreamId()).WillOnce(Return(54321));
65:         decoder_ = &conn_manager_->newStream(response_encoder_);
66: 
67:         // Test not charging stats on the second call.
68:         if (data.length() == 4) {
69:           RequestHeaderMapPtr headers{new TestRequestHeaderMapImpl{
70:               {":authority", "host"}, {":path", "/"}, {":method", "GET"}}};
71:           decoder_->decodeHeaders(std::move(headers), true);
72:         } else {
73:           RequestHeaderMapPtr headers{new TestRequestHeaderMapImpl{
74:               {":authority", "host"}, {":path", "/healthcheck"}, {":method", "GET"}}};
75:           EXPECT_EQ(54321, decoder_->streamInfo().codecStreamId());
76:           decoder_->decodeHeaders(std::move(headers), true);
77:         }
78: 
79:         ResponseHeaderMapPtr response_headers{new TestResponseHeaderMapImpl{{":status", "200"}}};
80:         filter->callbacks_->streamInfo().setResponseCodeDetails("");
81:         filter->callbacks_->encodeHeaders(std::move(response_headers), true, "details");
82:         response_encoder_.stream_.codec_callbacks_->onCodecEncodeComplete();
83: 
84:         // Drain 2 so that on the 2nd iteration we will hit zero.
85:         data.drain(2);
86:         return Http::okStatus();
87:       }));
88: 
89:   // Kick off the incoming data. Use extra data which should cause a redispatch.
90:   Buffer::OwnedImpl fake_input("1234");
91:   conn_manager_->onData(fake_input, false);
92: 
93:   EXPECT_EQ(1U, stats_.named_.downstream_rq_2xx_.value());
94:   EXPECT_EQ(1U, listener_stats_.downstream_rq_2xx_.value());
95:   EXPECT_EQ(1U, stats_.named_.downstream_rq_completed_.value());
96:   EXPECT_EQ(1U, listener_stats_.downstream_rq_completed_.value());
97: }
