677: bool ConnectionManagerImpl::isPrematureRstStream(const ActiveStream& stream) const {
678:   // Check if the request was prematurely reset, by comparing its lifetime to the configured
679:   // threshold.
680:   ASSERT(!stream.state_.is_internally_destroyed_);
681:   absl::optional<std::chrono::nanoseconds> duration =
682:       stream.filter_manager_.streamInfo().currentDuration();
683: 
684:   // Check if request lifetime is longer than the premature reset threshold.
685:   if (duration) {
686:     const uint64_t lifetime = std::chrono::duration_cast<std::chrono::seconds>(*duration).count();
687:     const uint64_t min_lifetime = runtime_.snapshot().getInteger(
688:         ConnectionManagerImpl::PrematureResetMinStreamLifetimeSecondsKey, 1);
689:     if (lifetime > min_lifetime) {
690:       return false;
691:     }
692:   }
693: 
694:   // If request has completed before configured threshold, also check if the Envoy proxied the
695:   // response from the upstream. Requests without the response status were reset.
696:   // TODO(RyanTheOptimist): Possibly support half_closed_local instead.
697:   return !stream.filter_manager_.streamInfo().responseCode();
698: }
