1261:   auto validation_result = header_validator_->validateRequestTrailers(trailers);
1262:   std::string failure_details(validation_result.details());
1263:   if (validation_result.ok()) {
1264:     auto transformation_result = header_validator_->transformRequestTrailers(trailers);
1265:     if (transformation_result.ok()) {
1266:       return true;
1267:     }
1268:     failure_details = std::string(transformation_result.details());
