1273:   if (Grpc::Common::hasGrpcContentType(*request_headers_)) {
1274:     grpc_status = Grpc::Status::WellKnownGrpcStatus::Internal;
1275:   }
1276: 
1277:   filter_manager_.streamInfo().setResponseFlag(
1278:       StreamInfo::CoreResponseFlag::DownstreamProtocolError);
1279: 
1280:   // H/2 codec was resetting requests that were rejected due to headers with underscores,
1281:   // instead of sending 400. Preserving this behavior for now.
1282:   // TODO(#24466): Make H/2 behavior consistent with H/1 and H/3.
1283:   if (failure_details == UhvResponseCodeDetail::get().InvalidUnderscore &&
1284:       connection_manager_.codec_->protocol() == Protocol::Http2) {
