809: void FilterManager::addDecodedData(ActiveStreamDecoderFilter& filter, Buffer::Instance& data,
810:                                    bool streaming) {
811:   if (state_.filter_call_state_ == 0 ||
812:       (state_.filter_call_state_ & FilterCallState::DecodeHeaders) ||
813:       (state_.filter_call_state_ & FilterCallState::DecodeData) ||
814:       ((state_.filter_call_state_ & FilterCallState::DecodeTrailers) && !filter.canIterate())) {
815:     // Make sure if this triggers watermarks, the correct action is taken.
816:     state_.decoder_filters_streaming_ = streaming;
817:     // If no call is happening or we are in the decode headers/data callback, buffer the data.
818:     // Inline processing happens in the decodeHeaders() callback if necessary.
819:     filter.commonHandleBufferData(data);
820:   } else if (state_.filter_call_state_ & FilterCallState::DecodeTrailers) {
821:     // In this case we need to inline dispatch the data to further filters. If those filters
822:     // choose to buffer/stop iteration that's fine.
823:     decodeData(&filter, data, false, FilterIterationStartState::AlwaysStartFromNext);
824:   } else {
825:     IS_ENVOY_BUG("Invalid request data");
826:     sendLocalReply(Http::Code::BadGateway, "Filter error", nullptr, absl::nullopt,
827:                    StreamInfo::ResponseCodeDetails::get().FilterAddedInvalidRequestData);
828:   }
829: }
