880: void FilterManager::decodeMetadata(ActiveStreamDecoderFilter* filter, MetadataMap& metadata_map) {
881:   ScopeTrackerScopeState scope(&*this, dispatcher_);
882:   filter_manager_callbacks_.resetIdleTimer();
883: 
884:   // Filter iteration may start at the current filter.
885:   StreamDecoderFilters::Iterator entry =
886:       commonDecodePrefix(filter, FilterIterationStartState::CanStartFromCurrent);
887: 
888:   ASSERT(!(state_.filter_call_state_ & FilterCallState::DecodeMetadata));
889: 
890:   for (; entry != decoder_filters_.end(); entry++) {
891:     ENVOY_EXECUTION_SCOPE(trackedStream(), &(*entry)->filter_context_);
892:     // If the filter pointed by entry has stopped for all frame type, stores metadata and returns.
893:     // If the filter pointed by entry hasn't returned from decodeHeaders, stores newly added
894:     // metadata in case decodeHeaders returns StopAllIteration. The latter can happen when headers
895:     // callbacks generate new metadata.
896:     if (!(*entry)->processed_headers_ || (*entry)->stoppedAll()) {
897:       Http::MetadataMapPtr metadata_map_ptr = std::make_unique<Http::MetadataMap>(metadata_map);
898:       (*entry)->getSavedRequestMetadata()->emplace_back(std::move(metadata_map_ptr));
899:       return;
900:     }
901:     state_.filter_call_state_ |= FilterCallState::DecodeMetadata;
902:     FilterMetadataStatus status = (*entry)->handle_->decodeMetadata(metadata_map);
903:     state_.filter_call_state_ &= ~FilterCallState::DecodeMetadata;
904: 
905:     ENVOY_STREAM_LOG(trace, "decode metadata called: filter={} status={}, metadata: {}", *this,
906:                      (*entry)->filter_context_.config_name, static_cast<uint64_t>(status),
907:                      metadata_map);
908:     if (state_.decoder_filter_chain_aborted_) {
909:       // If the decoder filter chain has been aborted, then either:
910:       // 1. This filter has sent a local reply or GoAway from decode metadata.
911:       // 2. This filter is the terminal http filter, and an upstream HTTP filter has sent a local
912:       // reply.
913:       ASSERT((status == FilterMetadataStatus::StopIterationForLocalReply) ||
914:              (std::next(entry) == decoder_filters_.end()));
915:       executeLocalReplyIfPrepared();
916:       ENVOY_STREAM_LOG(trace,
917:                        "decodeMetadata filter iteration aborted due to local reply: filter={}",
918:                        *this, (*entry)->filter_context_.config_name);
919:       return;
920:     }
921: 
922:     // Add the processed metadata to the next entry.
923:     if (status == FilterMetadataStatus::ContinueAll && !(*entry)->canIterate()) {
924:       if (std::next(entry) != decoder_filters_.end()) {
925:         (*std::next(entry))
926:             ->getSavedRequestMetadata()
927:             ->emplace_back(std::make_unique<MetadataMap>(metadata_map));
928:       }
929:       (*entry)->commonContinue();
930:       return;
931:     }
932:   }
933: }
