971: StreamDecoderFilters::Iterator
972: FilterManager::commonDecodePrefix(ActiveStreamDecoderFilter* filter,
973:                                   FilterIterationStartState filter_iteration_start_state) {
974:   if (!filter) {
975:     return decoder_filters_.begin();
976:   }
977:   if (filter_iteration_start_state == FilterIterationStartState::CanStartFromCurrent &&
978:       (*(filter->entry()))->iterate_from_current_filter_) {
979:     // The filter iteration has been stopped for all frame types, and now the iteration continues.
980:     // The current filter's callback function has not been called. Call it now.
981:     return filter->entry();
982:   }
983:   return std::next(filter->entry());
984: }
