986: void DownstreamFilterManager::onLocalReply(StreamFilterBase::LocalReplyData& data) {
987:   state_.under_on_local_reply_ = true;
988:   filter_manager_callbacks_.onLocalReply(data.code_);
989: 
990:   for (auto entry : filters_) {
991:     if (entry->onLocalReply(data) == LocalErrorStatus::ContinueAndResetStream) {
992:       data.reset_imminent_ = true;
993:     }
994:   }
995:   state_.under_on_local_reply_ = false;
996: }
